		if err != nil || val == "" {
			ctx.Output.Info("Default (Screenshot date-time)")
		} else {
			ctx.Output.Info("%s", strings.TrimSpace(val))
		}
		return nil
	}

	input := ctx.Args[0]
	switch strings.ToLower(input) {
