func parseFloat(s string) (float64, error) {
	var f float64
	for _, c := range s {
		if c >= '0' && c <= '9' || c == '.' {
			f = f*10 + float64(c-'0')
			if c == '.' {
				f = f / 10
			}
		}
	}
	return f, nil
}

